/**
 * Returns a GeoJSON FeatureCollection of substrate polygons sourced from the
Alaska ShoreZone Coastal Habitat Mapping Program (NOAA AKR / ADF&G — public
domain, https://alaskafisheries.noaa.gov/shorezone/). Each polygon is a
ShoreZone intertidal-zone (ITZ) unit from the `AK_SZ_ITZ_Polygons` layer
whose `Mat_Desc` and `Form_Desc` attributes have been classified into a
CMECS broad substrate class (bedrock / gravel / sand / mud).

The server bundles a regional Alaska ShoreZone collection (refreshed
offline via `pnpm --filter @workspace/scripts run build-shorezone`) and
filters it to the dataset's AOI bbox at request time. Datasets whose AOI
does not overlap published ShoreZone polygon coverage receive an empty
FeatureCollection together with a `nearestCoverage` block in `metadata`
describing where real ShoreZone coverage actually exists.

 * @summary Real Alaska ShoreZone substrate polygons
 */
export const GetSubstrateParams = zod.object({
  "id": zod.coerce.string().describe('Dataset identifier')
})

export const GetSubstrateResponse = zod.object({
  "type": zod.enum(['FeatureCollection']),
  "features": zod.array(zod.object({
  "type": zod.enum(['Feature']),
  "properties": zod.object({
  "unitId": zod.string().describe('ShoreZone PHY_IDENT — stable unit identifier'),
  "substrate": zod.enum(['bedrock', 'gravel', 'sand', 'mud']).describe('CMECS broad substrate class'),
  "shoreZoneClass": zod.string().describe('Human-readable ShoreZone class (e.g. \"Rock Platform\", \"Clastic Beach\")'),
  "cmecsCode": zod.string().describe('CMECS substrate classification code and label'),
  "color": zod.string().describe('Suggested hex color for rendering'),
  "szMaterial": zod.string().nullish().describe('Raw ShoreZone Mat_Desc (Rock \/ Clastic \/ Biogenic)'),
  "szForm": zod.string().nullish().describe('Raw ShoreZone Form_Desc (Cliff \/ Platform \/ Beach \/ Tidal Flat \/ Marsh)'),
  "areaSqM": zod.number().nullish().describe('Polygon area in square metres from the upstream Area attribute'),
  "natsur": zod.string().nullish().describe('Per-feature citation \/ classification narrative. For NOAA ENC features\nthis is the raw S-57 NATSUR descriptor; for TPWD Texas lake-substrate\nfeatures this is the lake-survey narrative explaining why this polygon\nwas classified the way it was (used as the tooltip body).\n'),
  "natqua": zod.string().nullish().describe('Raw S-57 NATQUA qualifier (ENC features only)'),
  "encChart": zod.string().nullish().describe('Provenance link for this feature. For NOAA ENC features this is the\nchart number; for TPWD Texas lake-substrate features this is the\noutbound TPWD lake page URL shown as a \"↗ TPWD lake page\" link in\nthe substrate info card.\n')
}).describe('Per-feature properties for an Alaska ShoreZone substrate polygon.\n'),
  "geometry": zod.record(zod.string(), zod.unknown())
})),
  "metadata": zod.record(zod.string(), zod.unknown()).optional()
})


